//# Bitmask: Isolate Rightmost 1 Bit

// Credit: [Hacker's Delight](./reading.html#Warren2013), Section 2-1: Manipulating Rightmost Bits

// Use the following formula to isolate the rightmost 1-bit, producing 0 if
// none (e.g., 01011000 -> 00001000)

// This function can trivially implement a [Priority
// Arbiter](./Arbiter_Priority.html), with the highest priority given to the
// least-significant bit, and is the building block of more complex arbiters.

`default_nettype none

module Bitmask_Isolate_Rightmost_1_Bit
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    word_in,
    output  reg     [WORD_WIDTH-1:0]    word_out
);

    initial begin
        word_out = {WORD_WIDTH{1'b0}};
    end

    always @(*) begin
        word_out = word_in & (-word_in);
    end

endmodule

//# Turn Off Rightmost 1 Bit

// Credit: [Hacker's Delight](./reading.html#Warren2013), Section 2-1: Manipulating Rightmost Bits

//Use the following formula to turn off the rightmost 1-bit in a word,
//producing 0 if none (e.g., 01011000 -> 01010000)

//This can be used to determine if an unsigned integer is a power of 2 or is
//0: apply the formula followed by a 0-test on the result.

`default_nettype none

module Turn_Off_Rightmost_1_Bit
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    word_in,
    output  reg     [WORD_WIDTH-1:0]    word_out
);

    initial begin
        word_out = {WORD_WIDTH{1'b0}};
    end

    localparam ONE = {{WORD_WIDTH-1{1'b0}},1'b1};

    always @(*) begin
        word_out = word_in & (word_in - ONE);
    end

endmodule

//# Bitmask: Thermometer from Count

// Credit: [Hacker's Delight](./reading.html#Warren2013), Section 2-1: Manipulating Rightmost Bits

// Sets the first N least-significant bits given integer N.
// If N is greater than WORD_WIDTH, then the mask is all-ones.

// This thermometer bitmask is also the lexicographically first member of the
// set of bitmasks with a given number of set bits (that is, with a constant
// population count). The last member is the same sequence, but with the bit
// order reversed (see: [Word Reverser](./Word_Reverser.html)). To generate
// all members, use [Bitmask: Next with Constant
// Popcount](./Bitmask_Next_with_Constant_Popcount.html).

`default_nettype none

module Bitmask_Thermometer_from_Count
#(
    parameter WORD_WIDTH    = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    count_in,
    output  reg     [WORD_WIDTH-1:0]    word_out
);

    localparam ONE = {{WORD_WIDTH-1{1'b0}},1'b1};

    initial begin
        word_out = {WORD_WIDTH{1'b0}};
    end

    always @(*) begin
        word_out = (ONE << count_in) - ONE;
    end

endmodule

//# Bitmask: Next with Constant Popcount (via Number of Trailing Zeros)

// Credit: [Hacker's Delight](./reading.html#Warren2013), Section 2-1: Manipulating Rightmost Bits, "A Novel Application"

// Given a bitmask, gives the next bitmask, in lexicographic order (a.k.a.
// strictly incrementing order), with the same number of bits set (a.k.a. same
// population count). For example: 00100011 -> 00100101.

// Modified here to wraparound correctly at the end of the word, which allows
// you to start with any given bitmask, then know you have tried all possible
// cases when the next bitmask is identical to the starting bitmask.  This
// property avoids having to calculate n-choose-k (for a k-bit bitmask in an
// n-bit word) as a count, or have to detect and handle the highest-valued
// bitmask (i.e.: 11100000) as a special case.

// Implementation, for x -> y:

// * s = x & -x
// * r = s + x
// * c = carry(s + x)
// * y = r | [((x^r) >> (2-2c)) / s]

// While this version requires a division (unlike the [popcount-based
// version](./Bitmask_Next_with_Constant_Popcount_pop.html)), the divisor (s)
// is always a power-of-two ([Bitmask: Isolate Rightmost
// 1 Bit](./Bitmask_Isolate_Rightmost_1_Bit.v)), so the (unsigned) division
// simplifies to a logical shift right by log<sub>2</sub>(s). The two
// consecutive logical shift right can now be combined or commuted, and
// ultimately reduce to a shift by the number of trailing zeros (ntz), with a
// correction of 2 or 0:

// * y = r | [((x^r) >> (2-2c)) >> log<sub>2</sub>(s)]
// * y = r | (x^r) >> [(2-2c) + log<sub>2</sub>(s)]
// * y = r | (x^r) >> [(2-2c) + ntz(x)]

// We will use the first above form since it doesn't require another adder of
// yet another bit width (log<sub>2</sub>(WORD_WIDTH)) which complicates
// writing clean Verilog, and the correction shift is predictable: either by
// 2 or zero, so we can provide both, select one, and feed it to the second,
// data-dependent shift.

// While this version replaces the relatively large [Population
// Count](./Population_Count.html) module with the much smaller [Logarithm of
// Powers of Two](./Logarithm_of_Powers_of_Two.html) module, it does require
// a full-word variable bit-shift, which costs more. I don't yet know whether
// this is a good tradeoff for speed or area.

`default_nettype none

module Bitmask_Next_with_Constant_Popcount_ntz
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    word_in,
    output  reg     [WORD_WIDTH-1:0]    word_out
);

// First, let's define some constants used throughout. Rather than expect
// the simulator/synthesizer to get the Verilog spec right and extend
// integers correctly, we defensively specify the entire word.

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

    initial begin
        word_out = WORD_ZERO;
    end

// Compute `s`: the least-significant bit set in the bitmask.

    wire [WORD_WIDTH-1:0] smallest;

    Bitmask_Isolate_Rightmost_1_Bit
    #(
        .WORD_WIDTH (WORD_WIDTH)
    )
    find_smallest
    (
        .word_in    (word_in),
        .word_out   (smallest)
    );

// Compute `r`: add that least-significant bit to the input, causing any run
// of consecutive 1 bits at the right to ripple up into the next 0 bit. (e.g.:
// 1001100 -> 1010000)

// Compute `c`: save the carry-out to later deal with the case where the
// consecutive 1 bits were at the left end of the word and rippled up into the
// carry out. In this case, we want to remove a correction to the shift amount
// described later.

    wire [WORD_WIDTH-1:0]   ripple;
    wire                    ripple_carry_out;

    Adder_Subtractor_Binary
    #(
        .WORD_WIDTH (WORD_WIDTH)
    )
    calc_ripple
    (
        .add_sub    (1'b0), // 0/1 -> A+B/A-B
        .carry_in   (1'b0),
        .A          (word_in),
        .B          (smallest),
        .sum        (ripple),
        .carry_out  (ripple_carry_out),
        // verilator lint_off PINCONNECTEMPTY
        .carries    (),
        .overflow   ()
        // verilator lint_on  PINCONNECTEMPTY
    );

// Compute `x^r`: find the bits which changed after the ripple
// addition. Any changed bits are on the right side of the ripple: the left
// side is always unchanged, except at the limit case where the carry out is
// set.

    reg [WORD_WIDTH-1:0] changed_bits = WORD_ZERO;

    always @(*) begin
        changed_bits = word_in ^ ripple;
    end

// We need a correction to the upcoming right shift: If we have not reached
// the left end of the word, then we need an extra right shift of two, else of
// zero.  Normally, after the ripple, we shift right once to discard the
// now-cleared least-significant set bit, and once more to bring the new
// least-significant set bit into the position of that original
// least-significant set bit. If we rippled right up into the carry bit, then
// no new least-significant set bit is created, so we don't have anything to
// discard and so we don't shift left here.

    reg [WORD_WIDTH-1:0] changed_bits_corrected = WORD_ZERO;

    always @(*) begin
        changed_bits_corrected = (ripple_carry_out == 1'b1) ? changed_bits : changed_bits >> 2;
    end

// Later, we will need to re-align our changed bits back to the right (plus
// any correction), so let's find out the index of the original
// least-significant set bit.

    wire [WORD_WIDTH-1:0] final_shift_amount;

    Logarithm_of_Powers_of_Two
    #(
        .WORD_WIDTH             (WORD_WIDTH)
    )
    calc_final_shift_amount
    (
        .one_hot_in             (smallest),
        .logarithm_out          (final_shift_amount),
        // verilator lint_off PINCONNECTEMPTY
        .logarithm_undefined    ()
        // verilator lint_on  PINCONNECTEMPTY
    );

// Now we shift the post-ripple changed bits (x^r) back to the right end of
// the word (plus correction), giving us the next sequence of changed bits
// with the same number of bits set.

    wire [WORD_WIDTH-1:0] changed_bits_shifted; 

    Bit_Shifter
    #(
        .WORD_WIDTH         (WORD_WIDTH)
    )
    move_changed_bits
    (
        .word_in_left       (WORD_ZERO),
        .word_in            (changed_bits_corrected),
        .word_in_right      (WORD_ZERO),

        .shift_amount       (final_shift_amount),
        .shift_direction    (1'b1), // 0/1 -> left/right

        // verilator lint_off PINCONNECTEMPTY
        .word_out_left      (),
        .word_out           (changed_bits_shifted),
        .word_out_right     ()
        // verilator lint_on  PINCONNECTEMPTY
    );

// Finally, we OR the rippled bits (which contains the unchanged left-most
// part, plus the newly set/cleared ripple bits) with the changed bits lost to
// the initial ripple (if any). We now have the next bitmask with the same
// number of set bits, in strict incrementing order (a.k.a. lexicographic
// order).

    always @(*) begin
        word_out = ripple | changed_bits_shifted;
    end

endmodule

//# Logarithm of Powers of Two

// Translates a power-of-2 binary value (a one-hot bitmask) into its integer
// base-2 logarithm. For example:

// * log<sub>2</sub>(0001) -> log<sub>2</sub>(2<sup>0</sup>) -> log<sub>2</sub>(1) -> 0
// * log<sub>2</sub>(0010) -> log<sub>2</sub>(2<sup>1</sup>) -> log<sub>2</sub>(2) -> 1
// * log<sub>2</sub>(0100) -> log<sub>2</sub>(2<sup>2</sup>) -> log<sub>2</sub>(4) -> 2
// * log<sub>2</sub>(1000) -> log<sub>2</sub>(2<sup>3</sup>) -> log<sub>2</sub>(8) -> 3

// We can see the logarithm of a power-of-2 is simply the index of the single
// set bit: log<sub>2</sub>(2<sup>set_bit_index</sup>) = set_bit_index.

// If the input is not a power-of-2 (more than one set bit), then this
// implementation will output the bitwise-OR of the logarithm of each set bit
// treated as a power-of-2, which I'm not sure has any use or meaning. To save
// hardware (we'd need a [Population Count](./Population_Count.html) or a pair
// of [priority bitmasks](./Bitmask_Isolate_Rightmost_1_Bit.html)), we don't signal these
// cases.
// Also, this calculation fails if no bits are set, since log<sub>2</sub>(0)
// is undefined, and we cannot output zero as that's a valid logarithm. To
// represent the undefined case, we will set an extra bit to declare the output
// undefined, via a simple NOR-reduction of the input.

// We can't implement using a translation table, as with the
// [Static Address Translator](./Address_Translator_Static.html), since we
// would have to create a table capable of holding all 2<sup>WORD_WIDTH</sup>
// possible values, and that would take a *long* time to synthesize and optimize,
// as well as require a lot of system memory.
// Instead, we precalculate each possible logarithm (one per input bit) and
// gate its value based on whether the corresponding input bit is set. We then
// OR-reduce all these possible logarithms into the final answer. We can use
// this implementation method since the amount of logic scales linearly with
// WORD_WIDTH.

// You can use this module to implement unsigned division by powers-of-2 by
// shifting right by the logarithm value. However, *signed* division by
// powers-of-2 has a complication. See [Hacker's
// Delight](./reading.html#Warren2013), Section 10-1, "Signed Division by
// a Known Power of 2". 

// When combined with [Bitmask: Isolate Rightmost
// 1 Bit](./Bitmask_Isolate_Rightmost_1_Bit.html), this module forms the basis
// for the very useful Number of Trailing Zeros (ntz) function. Add a [Word
// Reverser](./Word_Reverser.html) and you can compute Number of Leading Zeros
// (nlz).

`default_nettype none

module Logarithm_of_Powers_of_Two
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    one_hot_in,
    output  wire    [WORD_WIDTH-1:0]    logarithm_out,
    output  reg                         logarithm_undefined
);

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

    initial begin
        logarithm_undefined = 1'b0;
    end

// To keep the interface clean, logarithm_out has the same WORD_WIDTH as
// one_hot_in. To calculate each possbile logarithm in parallel, we need an
// array of one output word per input bit. But we must use a flat vector here
// instead of an array since we will be passing this vector of words to
// a Word_Reducer module, and we can't pass multidimensional arrays through
// module ports in Verilog-2001. This means you will hit the Verilog vector
// width limit of about a million when WORD_WIDTH reaches about 1024, though
// simulation and synthesis will have become impractically slow long before
// then.

    localparam TOTAL_WIDTH  = WORD_WIDTH * WORD_WIDTH;
    localparam TOTAL_ZERO   = {TOTAL_WIDTH{1'b0}};

    reg [TOTAL_WIDTH-1:0] all_logarithms = TOTAL_ZERO;

// Most of those logarithm output bits remain a constant zero (and so require
// no logic) since representing the value of a binary number up to
// 2<sup>N</sup>-1 require at most log<sub>2</sub>(N) bits. Therefore,
// representing log<sub>2</sub>(2<sup>N</sup>-1) in binary only needs
// log<sub>2</sub>(log<sub>2</sub>(N)) bits, which is a value that grows
// __very__ slowly. Having output bits stuck at zero will raise CAD tool
// warnings, but that's a lot less error-prone than having the enclosing logic
// calculate the required output logarithm bit width.

// This implementation would ultimately fail if the computed logarithm needs
// more bits than a 32-bit Verilog integer. However, as explained above, that
// would require an input value exceeding 2<sup>2<sup>32</sup></sup>-1, which
// is 2<sup>32</sup> bits long. You are not likely to reach this limit.

// So we pre-compute how many bits we will need to represent the logarithm,
// and also create some zero-padding to expand the logarithm back to
// WORD_WIDTH.

    `include "clog2_function.vh"
    localparam LOGARITHM_WIDTH = clog2(WORD_WIDTH);
    localparam PAD_WIDTH = WORD_WIDTH - LOGARITHM_WIDTH;
    localparam PAD = {PAD_WIDTH{1'b0}};

// Then, for each set input bit, put its logarithm (the bit index) into the
// corresponding array word, else put zero. Note how we slice the integer
// logarithm down to the necessary bits and then pad those back up to the
// array word width.

    generate
        genvar i;
        for(i = 0; i < WORD_WIDTH; i = i + 1) begin : per_input_bit
            always @(*) begin
                all_logarithms[WORD_WIDTH*i +: WORD_WIDTH] = (one_hot_in[i] == 1'b1) ? {PAD, i[LOGARITHM_WIDTH-1:0]} : WORD_ZERO;
            end
        end
    endgenerate

// Then, we OR-reduce the array of possible logarithms down to one.

    Word_Reducer
    #(
        .OPERATION  ("OR"),
        .WORD_WIDTH (WORD_WIDTH),
        .WORD_COUNT (WORD_WIDTH)
    )
    combine_logarithms
    (
        .words_in   (all_logarithms),
        .word_out   (logarithm_out)
    );

// Finally, we detect the case where all input bits are zero and the logarithm
// is undefined.

    always @(*) begin
        logarithm_undefined = (one_hot_in == WORD_ZERO);
    end

endmodule

//# Bit Shifter

// This module is a building block for application-specific shifts and
// rotates. It synthesizes to LUT logic and can be quite large if not
// specialized to a particular situation.

//## A Warning About Shift Right and Signed Division

// While a left shift by N is always equivalent to a multiplication by
// 2<sup>N</sup> for both signed and unsigned binary integers, an arithmetic
// shift right by N is only a truncating division by 2<sup>N</sup> for
// *positive* binary integers. For negative integers, the result is so-called
// modulus division, and the quotient ends up off by one in magnitude, and
// must be corrected by adding +1, *but only if an odd number results as part
// of the intermediate division steps*. That is, if a non-zero bit was shifted
// out to the right.

// To implement proper signed division by a power-of-two, use the <a
// href="./Divider_Integer_Signed_by_Powers_of_Two.html">Integer Divider by
// Power of Two</a> module, which performs the correction for negative
// numbers and also calculates the remainder as a bonus.

//## Usage

// We can treat the `shift_amount` and the `shift_direction` together as
// a signed magnitude number: the amount is an absolute value, and the
// direction is the sign of the value. Here, a `shift_direction` of `1`,
// meaning a negative number, shifts to the right. Choosing this convention
// for the sign matches the behaviour of a shift when we think about it as
// a multiplication or division by a power of 2:

// * Multipliying by 8 is equivalent to 2<sup>3</sup>N, which is
// a shift-left by 3 steps.
// * Dividing N by 4 is equivalent to 2<sup>-2</sup>N, which is
// a shift-right by 2 steps.

// Adding together these multiples and fractions generated by the shifts
// enables the creation of small, cheap scaling by constant ratios:

// * 3N = N + 2<sup>1</sup>N
// * 10N = 8N + 2N = 2<sup>3</sup>N + 2<sup>1</sup>N
// * 5N/4 = N + N/4 = N + 2<sup>-2</sup>N
// * etc...

// When the shift values are constant, the shifter reduces to simple rewiring,
// which in turn reduces the above examples to an adder or two each.

// The shifts are internally unsigned and `word_in` and `word_out` are
// extended to the left and right so new bits can be shifted in and current
// bits shifted out without loss, regardless of shift amount or direction,
// which enables the creation of more complex shifts or rotates:

// * Wire the most-significant bit (MSB) of `word_in` to all `word_in_left` inputs and zero to all `word_in_right` inputs to create a signed arithmetic shift.
// * Wire the `word_in` MSB to `word_in_right` MSB (or vice-versa) to create a rotate function.
// * Feed `word_out_left` and `word_out` to a double-word adder and set the
// shift to +1 (left by 1) as part of the construction of a conditional-add
// multiplier, which multiplies two N-bit words in N cycles, giving a 2N-bit
// result.

`default_nettype none

module Bit_Shifter
#(
    parameter   WORD_WIDTH  = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    word_in_left,
    input   wire    [WORD_WIDTH-1:0]    word_in,
    input   wire    [WORD_WIDTH-1:0]    word_in_right,

    input   wire    [WORD_WIDTH-1:0]    shift_amount,
    input   wire                        shift_direction, // 0/1 -> left/right

    output  reg     [WORD_WIDTH-1:0]    word_out_left,
    output  reg     [WORD_WIDTH-1:0]    word_out,
    output  reg     [WORD_WIDTH-1:0]    word_out_right
);

// Let's document the shift direction convention again here, and define our
// initial values for the outputs and the intermediate result.

    localparam  LEFT_SHIFT  = 1'b0;
    localparam  RIGHT_SHIFT = 1'b1;

    localparam  TOTAL_WIDTH = WORD_WIDTH * 3;
    localparam  TOTAL_ZERO  = {TOTAL_WIDTH{1'b0}};
    localparam  WORD_ZERO   = {WORD_WIDTH{1'b0}};

    initial begin
        word_out_left    = WORD_ZERO;
        word_out         = WORD_ZERO;
        word_out_right   = WORD_ZERO;
    end 

    reg [TOTAL_WIDTH-1:0] word_in_total = TOTAL_ZERO;

// Rather than do arithmetic and calculate slices of vectors to figure out
// where the shifted bits end up, let's concatenate the input words into one
// triple-wide word, shift it as an unsigned number, then deconcatenate the
// result into each output word. All we have to do is keep the same convention
// on bit significance: here LSB is on the right.

    always @(*) begin
        word_in_total = {word_in_left, word_in, word_in_right};
        {word_out_left, word_out, word_out_right} = (shift_direction == LEFT_SHIFT) ? word_in_total << shift_amount : word_in_total >> shift_amount; 
    end

endmodule

//# Word Reverser

// Reverses the order of words in the input vector, composed of concatenated
// words, with the first word at the right.  We can't reverse vectors via
// reversed indices in Verilog, so we must use a for loop to manually move the
// bits around.

// The `WORD_WIDTH` and `WORD_COUNT` parameters express how the input vector
// is split-up, and so defines which reversal happens. The total width is
// always the product of the word width and count. For example:

// * `WORD_WIDTH = 1` and `WORD_COUNT = 32` reverses all the bits in a 32-bit word.
// * `WORD_WIDTH = 8` and `WORD_COUNT = 4` reverses the endianness of bytes in a 32-bit word.

// There is no clock or Boolean logic, and everything is computed at
// elaboration time, so this module simply moves wires around and consumes no
// logic resources.

`default_nettype none

module Word_Reverser
#(
    parameter WORD_WIDTH = 0,
    parameter WORD_COUNT = 0,

    // Do not set at instantiation
    parameter TOTAL_WIDTH = WORD_WIDTH * WORD_COUNT
)
(
    input   wire    [TOTAL_WIDTH-1:0]   words_in,
    output  reg     [TOTAL_WIDTH-1:0]   words_out
);

    initial begin
        words_out = {TOTAL_WIDTH{1'b0}};
    end

// For each input word, starting from the right, place it in the output word,
// but starting at the left.

    generate
        genvar i;
        for (i=0; i < WORD_COUNT; i=i+1) begin : per_word
            always @(*) begin
                words_out[WORD_WIDTH*(WORD_COUNT-i-1) +: WORD_WIDTH] = words_in[WORD_WIDTH*i +: WORD_WIDTH];
            end
        end
    endgenerate

endmodule

//# Bitmask: Next with Constant Popcount (via Population Count)

// Credit: [Hacker's Delight](./reading.html#Warren2013), Section 2-1: Manipulating Rightmost Bits, "A Novel Application"

// Given a bitmask, gives the next bitmask, in lexicographic order (a.k.a.
// strictly incrementing order), with the same number of bits set (a.k.a. same
// population count). For example: 00100011 -> 00100101.

// Modified here to wraparound correctly at the end of the word, which allows
// you to start with any given bitmask, then know you have tried all possible
// cases when the next bitmask is identical to the starting bitmask.  This
// property avoids having to calculate n-choose-k (for a k-bit bitmask in an
// n-bit word) as a count, or have to detect and handle the highest-valued
// bitmask (i.e.: 11100000) as a special case.

// Implementation, for x -> y:

// * s = x & -x
// * r = s + x
// * c = carry(s + x)
// * y = r | [(1 << (popcount(x^r)-2-2c))-1]

// While this version uses the relatively large [Population
// Count](./Population_Count.html) module instead of the much smaller
// [Logarithm of Powers of Two](./Logarithm_of_Powers_of_Two.html) module, its
// variable bit-shift is only for the fixed input value of 1, which requires
// much less hardware than the full-word shifter found in the [ntz-based
// version](./Bitmask_Next_with_Constant_Popcount_ntz.html). I don't yet know
// whether this is a good tradeoff for speed or area.

`default_nettype none

module Bitmask_Next_with_Constant_Popcount_pop
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    word_in,
    output  reg     [WORD_WIDTH-1:0]    word_out
